+            .unwrap();
+        conn.execute("INSERT INTO hc VALUES ('X', 1), ('Y', 2), ('X', 3);")
+            .unwrap();
+        // CASE grp WHEN 'X' THEN 1 ELSE 0 END = 1 keeps only 'X'
+        let rows = conn
+            .query("SELECT grp, SUM(val) FROM hc GROUP BY grp HAVING CASE grp WHEN 'X' THEN 1 ELSE 0 END = 1;")
+            .unwrap();
